// generateRandomState generates a cryptographically secure random string for the OAuth2 state parameter.
func generateRandomState() string {
	b := make([]byte, 32)
	_, err := rand.Read(b)
	if err != nil {
		// In case of entropy failure, panic or handle appropriately. 
		// For this context, we panic as secure random is critical.
		panic(err)
	}
	return base64.URLEncoding.EncodeToString(b)
}

// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter allows customization of where the user should be redirected after auth.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Security Fix 1: Validate the user-provided redirectPath to prevent Open Redirect vulnerabilities.
	// Ensure the redirect URL matches the application's domain or is a relative path.
	parsedURL, err := url.Parse(redirectPath)
	if err != nil {
		return "", err
	}

	// If the redirect URL is relative (no scheme and no host), resolve it against the default RedirectURL.
	if parsedURL.Scheme == "" && parsedURL.Host == "" {
		baseURL, err := url.Parse(OAuthConfig.RedirectURL)
		if err != nil {
			return "", err
		}
		redirectPath = baseURL.ResolveReference(parsedURL).String()
	} else {
		// If the redirect URL is absolute, strictly verify that it points to the allowed domain.
		// This prevents attackers from redirecting users to malicious sites (e.g., redirectPath = "https://evil.com").
		baseURL, err := url.Parse(OAuthConfig.RedirectURL)
		if err != nil {
			return "", err
		}
		if parsedURL.Host != baseURL.Host {
			return "", http.ErrUseLastResponse // Or return a specific error for invalid domain
		}
	}

	// Security Fix 2: Use a cryptographically secure random string for the state parameter
	// to prevent CSRF (Cross-Site Request Forgery) attacks.
	state := generateRandomState()

	// Create a copy of the OAuth config with the validated redirect URL
	config := *OAuthConfig
	config.RedirectURL = redirectPath

	// Generate the authorization URL
	authURL := config.AuthCodeURL(state)

	// Set the state in a cookie for later validation
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteLaxMode,
		Path:     "/",
	})

