// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter allows customization of where the user should be redirected after auth.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Generate a cryptographically secure random state
	b := make([]byte, 32)
	if _, err := rand.Read(b); err != nil {
		return "", err
	}
	state := base64.URLEncoding.EncodeToString(b)

	// Validate the user-provided redirectPath to prevent Open Redirect vulnerabilities.
	// It must match the base URL configured in OAuthConfig.
	// Note: This logic assumes OAuthConfig.RedirectURL is absolute. 
	// If relative paths are used, additional parsing logic is required.
	if redirectPath != "" {
		// Parse the configured base URL to get the Scheme and Host
		baseURL, err := url.ParseRequestURI(OAuthConfig.RedirectURL)
		if err != nil {
			return "", err
		}

		// Parse the user-provided redirect path
		redirectURL, err := url.ParseRequestURI(redirectPath)
		if err != nil {
			return "", err
		}

		// Ensure the scheme and host match exactly to prevent redirecting to external domains
		if baseURL.Scheme != redirectURL.Scheme || baseURL.Host != redirectURL.Host {
			return "", &url.Error{Op: "Parse", URL: redirectPath, Err: http.ErrNotSupported}
		}
	}

	// Create a copy of the OAuth config with the validated redirect URL
	config := *OAuthConfig
	config.RedirectURL = redirectPath

	// Generate the authorization URL
	authURL := config.AuthCodeURL(state)

	// Set the state in a cookie for later validation
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteLaxMode,
		Path:     "/",
	})

	return authURL, nil
}

