// The redirectPath parameter allows customization of where the user should be redirected after auth.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// 1. Validate the user-provided redirectPath to prevent Open Redirect vulnerabilities.
	parsedURL, err := url.Parse(redirectPath)
	if err != nil {
		return "", err
	}

	// Ensure the URL is absolute and uses HTTPS.
	if parsedURL.Scheme != "https" {
		return "", http.ErrUseLastResponse
	}

	// Ensure the host matches the application's domain to prevent redirects to external sites.
	// We compare the host of the redirectPath with the host of the configured OAuthConfig.
	configBaseURL, _ := url.Parse(OAuthConfig.RedirectURL)
	if parsedURL.Host != configBaseURL.Host {
		return "", http.ErrUseLastResponse
	}

	// 2. Generate a cryptographically random state parameter to prevent CSRF attacks.
	state := generateRandomState()

	// 3. Create a copy of the OAuth config with the validated redirect URL
	config := *OAuthConfig
	config.RedirectURL = redirectPath

	// 4. Generate the authorization URL
	authURL := config.AuthCodeURL(state)

	// 5. Set the state in a cookie for later validation
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteLaxMode,
		Path:     "/",
	})

	return authURL, nil
}

// generateRandomState creates a random string for the OAuth2 state parameter.
// This requires "crypto/rand" and "encoding/hex".
func generateRandomState() string {
	b := make([]byte, 16)
	// Note: In a real application, ensure you handle the error from rand.Read appropriately.
	// For this snippet, we assume full reads or panic on failure to ensure security.
	_, err := rand.Read(b)
	if err != nil {
		panic("failed to generate random state: " + err.Error())
	}
	return hex.EncodeToString(b)
