func generateRandomState() (string, error) {
	b := make([]byte, 32)
	_, err := rand.Read(b)
	if err != nil {
		return "", err
	}
	return base64.URLEncoding.EncodeToString(b), nil
}

// GenerateAuthURL generates an OAuth2 authorization URL for the user to authenticate.
// The redirectPath parameter allows customization of where the user should be redirected after auth.
func GenerateAuthURL(redirectPath string, session *http.Cookie, w http.ResponseWriter, r *http.Request) (string, error) {
	// Validate the user-provided redirectPath to prevent Open Redirect vulnerabilities.
	// It must be a valid URL and belong to the allowed domain.
	parsedURL, err := url.Parse(redirectPath)
	if err != nil {
		return "", err
	}

	// Ensure the scheme is https (or http for localhost development)
	if parsedURL.Scheme != "https" && (parsedURL.Scheme != "http" || parsedURL.Hostname() != "localhost") {
		return "", url.InvalidHostError("Scheme must be https or http for localhost")
	}

	// Ensure the host matches the application's domain to prevent redirecting to external sites.
	// This uses the RedirectURL configured in OAuthConfig as the source of truth for allowed domains.
	baseURL, err := url.Parse(OAuthConfig.RedirectURL)
	if err != nil {
		return "", err
	}

	if parsedURL.Hostname() != baseURL.Hostname() {
		return "", url.InvalidHostError("Redirect host does not match allowed domain")
	}

	// Generate a cryptographically random state parameter to prevent CSRF attacks.
	state, err := generateRandomState()
	if err != nil {
		return "", err
	}

	// Create a copy of the OAuth config with the validated redirect URL
	config := *OAuthConfig
	config.RedirectURL = redirectPath

	// Generate the authorization URL
	authURL := config.AuthCodeURL(state)

	// Set the state in a cookie for later validation
	http.SetCookie(w, &http.Cookie{
		Name:     "oauth_state",
		Value:    state,
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteLaxMode,
		Path:     "/",
	})

	return authURL, nil
}

